attributes.cssVariables:
:root {
  --blog-color-bg: #fcf8f1;
  --blog-color-text: #1a1410;
  --blog-color-body: #2b2520;
  --blog-color-muted: #5b4f47;
  --blog-color-subtle: #7a6b60;
  --blog-color-faint: #a89c92;
  --blog-color-placeholder: #c4b8ad;
  --blog-color-thumb-bg: #efe8db;
  --blog-color-divider: #e0d6c6;
  --blog-color-accent: #b1395a;
  --blog-color-card-bg: #fffdf8;
  --blog-font-family: 'Lora', Georgia, 'Times New Roman', serif;
  --blog-font-display-family: 'Playfair Display', Georgia, serif;
  --blog-font-headline: 700 4.25rem/1.05 var(--blog-font-display-family);
  --blog-font-display-l: 700 2.75rem/1.1 var(--blog-font-display-family);
  --blog-font-display-m: 700 2.1rem/1.15 var(--blog-font-display-family);
  --blog-font-name: 700 1.6rem/1.2 var(--blog-font-display-family);
  --blog-font-h2: 700 1.9rem/1.25 var(--blog-font-display-family);
  --blog-font-h3: 700 1.3rem/1.35 var(--blog-font-display-family);
  --blog-font-subtitle: italic 400 1.3rem/1.5 var(--blog-font-family);
  --blog-font-pullquote: italic 500 1.55rem/1.4 var(--blog-font-display-family);
  --blog-font-body: 400 1.0625rem/1.75 var(--blog-font-family);
  --blog-font-body-sm: 400 0.95rem/1.65 var(--blog-font-family);
  --blog-font-meta: 500 0.72rem/1 var(--blog-font-family);
  --blog-font-eyebrow: 600 0.72rem/1 var(--blog-font-family);
  --blog-tracking-meta: 0.08em;
  --blog-tracking-eyebrow: 0.22em;
  --blog-tracking-tight: 0;
  --blog-tracking-tighter: 0;
  --blog-reading-max: 680px;
  --blog-subtitle-max: 720px;
  --blog-headline-max: 880px;
  --blog-canvas-max: 1100px;
  --blog-radius-md: 4px;
  --blog-radius-pill: 999px;
  --blog-shadow-card: 0 1px 2px rgba(60, 40, 20, 0.06);
  --blog-shadow-card-hover: 0 6px 18px rgba(60, 40, 20, 0.1);
  --blog-shadow-portrait: 0 6px 18px rgba(60, 40, 20, 0.12);
}
